struct Semaphore {
int value;
ProcessList pl;
};
down ()
{
value -= 1;
if (value < 0) {
// add this process to pl
Sleep ();
}
}
up () {
Process P;
value += 1;
if (value <= 0) {
// remove a process P
// from pl
Wakeup (P);
}
}
